#include <stdio.h>
#include <stdlib.h>
#define MAX_N 100000
#define MAX_M 100000
// Define the structure for a graph node
typedef struct Node {
    int weight;
    int* neighbors;
    int num_neighbors;
} Node;
// Function to calculate the maximum weight independent set
int max_weight_independent_set(Node* nodes, int num_nodes, int node_index, int* visited) {
    if (node_index >= num_nodes) return 0;
    if (visited[node_index] == 1) return 0;
    // Mark the current node as visited
    visited[node_index] = 1;
    int max_weight = nodes[node_index].weight;
    // Iterate over all neighbors of the current node
    for (int i = 0; i < nodes[node_index].num_neighbors; i++) {
        int neighbor_index = nodes[node_index].neighbors[i];
        // If the neighbor is not visited, calculate the maximum weight independent set for the neighbor
        if (visited[neighbor_index] == 0) {
            max_weight += max_weight_independent_set(nodes, num_nodes, neighbor_index, visited);
        }
    }
    // Unmark the current node as visited
    visited[node_index] = 0;
    return max_weight;
}
int main() {
    int N;
    scanf("%d", &N);
    Node* nodes = (Node*)malloc(N * sizeof(Node));
    for (int i = 0; i < N; i++) {
        scanf("%d", &nodes[i].weight);
        nodes[i].num_neighbors = 0;
        nodes[i].neighbors = NULL;
    }
    for (int i = 0; i < N - 1; i++) {
        int u, v;
        scanf("%d %d", &u, &v);
        u--; v--;
        nodes[u].num_neighbors++;
        nodes[v].num_neighbors++;
        nodes[u].neighbors = (int*)realloc(nodes[u].neighbors, nodes[u].num_neighbors * sizeof(int));
        nodes[v].neighbors = (int*)realloc(nodes[v].neighbors, nodes[v].num_neighbors * sizeof(int));
        nodes[u].neighbors[nodes[u].num_neighbors - 1] = v;
        nodes[v].neighbors[nodes[v].num_neighbors - 1] = u;
    }
    int* visited = (int*)malloc(N * sizeof(int));
    for (int i = 0; i < N; i++) visited[i] = 0;
    int max_weight = 0;
    for (int i = 0; i < N; i++) {
        max_weight = max_weight_independent_set(nodes, N, i, visited);
    }
    printf("%d\n", max_weight);
    return 0;
}

