#include <iostream>
#include <vector>
using namespace std;
#define MAX_N 100000
// Define the structure for a graph node
struct Node {
    int weight;
    vector<int> neighbors;
};
// Function to calculate the maximum weight independent set
int max_weight_independent_set(vector<Node>& nodes, int node_index, vector<bool>& visited) {
    if (node_index >= nodes.size()) return 0;
    if (visited[node_index]) return 0;
    // Mark the current node as visited
    visited[node_index] = true;
    int max_weight = nodes[node_index].weight;
    // Iterate over all neighbors of the current node
    for (int neighbor_index : nodes[node_index].neighbors) {
        // If the neighbor is not visited, calculate the maximum weight independent set for the neighbor
        if (!visited[neighbor_index]) {
            max_weight += max_weight_independent_set(nodes, neighbor_index, visited);
        }
    }
    // Unmark the current node as visited
    visited[node_index] = false;
    return max_weight;
}
int main() {
    int N;
    cin >> N;
    vector<Node> nodes(N);
    for (int i = 0; i < N; i++) cin >> nodes[i].weight;
    for (int i = 0; i < N - 1; i++) {
        int u, v;
        cin >> u >> v;
        u--; v--;
        nodes[u].neighbors.push_back(v);
        nodes[v].neighbors.push_back(u);
    }
    vector<bool> visited(N, false);
    int max_weight = 0;
    for (int i = 0; i < N; i++) {
        max_weight = max_weight_independent_set(nodes, i, visited);
    }
    cout << max_weight << endl;
    return 0;
}

