import java.util.ArrayList;
import java.util.List;
import java.util.Scanner;
public class Main {
    static class Node {
        int weight;
        List<Integer> neighbors;
        public Node(int weight) {
            this.weight = weight;
            this.neighbors = new ArrayList<>();
        }
    }
    public static int maxWeightIndependentSet(Node[] nodes, int nodeIndex, boolean[] visited) {
        if (nodeIndex >= nodes.length) return 0;
        if (visited[nodeIndex]) return 0;
        // Mark the current node as visited
        visited[nodeIndex] = true;
        int maxWeight = nodes[nodeIndex].weight;
        // Iterate over all neighbors of the current node
        for (int neighborIndex : nodes[nodeIndex].neighbors) {
            // If the neighbor is not visited, calculate the maximum weight independent set for the neighbor
            if (!visited[neighborIndex]) {
                maxWeight += maxWeightIndependentSet(nodes, neighborIndex, visited);
            }
        }
        // Unmark the current node as visited
        visited[nodeIndex] = false;
        return maxWeight;
    }
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        int N = scanner.nextInt();
        Node[] nodes = new Node[N];
        for (int i = 0; i < N; i++) {
            nodes[i] = new Node(scanner.nextInt());
        }
        for (int i = 0; i < N - 1; i++) {
            int u = scanner.nextInt() - 1;
            int v = scanner.nextInt() - 1;
            nodes[u].neighbors.add(v);
            nodes[v].neighbors.add(u);
        }
        boolean[] visited = new boolean[N];
        int maxWeight = 0;
        for (int i = 0; i < N; i++) {
            maxWeight = maxWeightIndependentSet(nodes, i, visited);
        }
        System.out.println(maxWeight);
    }
}

